// ============================================================================
// SIZE CONSTANTS
// ============================================================================

export const ICON_SIZES = { xxsmall: 8, xsmall: 12, small: 16, medium: 20, large: 32, xlarge: 64 };
export const BRAND_ICON_SIZES = { xsmall: 16, small: 20, medium: 32, large: 40 };
export const FLAG_ICON_SIZES = { xsmall: 16, small: 20, medium: 24, large: 32 };
export const CARD_ICON_SIZES = { xsmall: 24, small: 32, medium: 40, large: 48 };
export const PAYMENT_METHOD_ICON_SIZES = { xsmall: 16, small: 20, medium: 32, large: 40 };

// ============================================================================
// ICON COMPONENTS
// ============================================================================

/**
 * Icon - Colorable single-path icons
 */
export const Icon = forwardRef(function Icon(
  { name, size = 'small', fill = 'currentColor', className, style, ...props },
  ref
) {
  const pathData = iconPaths[name];
  if (!pathData) { console.warn(`Icon "${name}" not found`); return null; }
  const dimension = typeof size === 'number' ? size : ICON_SIZES[size] || ICON_SIZES.small;
  return (
    <svg ref={ref} width={dimension} height={dimension} viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" className={className} style={{ display: 'inline-block', verticalAlign: 'middle', ...style }} aria-hidden="true" {...props}>
      <path fillRule="evenodd" clipRule="evenodd" d={pathData} fill={fill} />
    </svg>
  );
});

/**
 * BrandIcon - Brand/company logos (fixed colors)
 */
export const BrandIcon = forwardRef(function BrandIcon(
  { name, size = 'medium', className, style, ...props },
  ref
) {
  const iconInfo = brandIconData[name];
  if (!iconInfo) { console.warn(`BrandIcon "${name}" not found`); return null; }
  const dimension = typeof size === 'number' ? size : BRAND_ICON_SIZES[size] || BRAND_ICON_SIZES.medium;
  const { viewBox, paths } = iconInfo;
  return (
    <svg ref={ref} width={dimension} height={dimension} viewBox={viewBox} fill="none" xmlns="http://www.w3.org/2000/svg" className={className} style={{ display: 'inline-block', verticalAlign: 'middle', ...style }} aria-hidden="true" {...props}>
      {paths.map((path, i) => <path key={i} d={path.d} fill={path.fill} fillRule={path.fillRule} clipRule={path.clipRule} opacity={path.opacity} />)}
    </svg>
  );
});

/**
 * FlagIcon - Country flags by ISO code
 */
export const FlagIcon = forwardRef(function FlagIcon(
  { name, size = 'medium', className, style, ...props },
  ref
) {
  const iconInfo = flagIconData[name];
  if (!iconInfo) { console.warn(`FlagIcon "${name}" not found`); return null; }
  const dimension = typeof size === 'number' ? size : FLAG_ICON_SIZES[size] || FLAG_ICON_SIZES.medium;
  const { viewBox, paths } = iconInfo;
  return (
    <svg ref={ref} width={dimension} height={dimension} viewBox={viewBox} fill="none" xmlns="http://www.w3.org/2000/svg" className={className} style={{ display: 'inline-block', verticalAlign: 'middle', ...style }} aria-hidden="true" {...props}>
      {paths.map((path, i) => <path key={i} d={path.d} fill={path.fill} fillRule={path.fillRule} clipRule={path.clipRule} opacity={path.opacity} />)}
    </svg>
  );
});

/**
 * CardIcon - Card brand icons (Visa, Mastercard, etc.)
 */
export const CardIcon = forwardRef(function CardIcon(
  { name, size = 'medium', className, style, ...props },
  ref
) {
  const iconInfo = cardIconData[name];
  if (!iconInfo) { console.warn(`CardIcon "${name}" not found`); return null; }
  const dimension = typeof size === 'number' ? size : CARD_ICON_SIZES[size] || CARD_ICON_SIZES.medium;
  const { viewBox, paths } = iconInfo;
  return (
    <svg ref={ref} width={dimension} height={dimension} viewBox={viewBox} fill="none" xmlns="http://www.w3.org/2000/svg" className={className} style={{ display: 'inline-block', verticalAlign: 'middle', ...style }} aria-hidden="true" {...props}>
      {paths.map((path, i) => <path key={i} d={path.d} fill={path.fill} fillRule={path.fillRule} clipRule={path.clipRule} opacity={path.opacity} />)}
    </svg>
  );
});

/**
 * PaymentMethodIcon - Payment method logos (colorable)
 */
export const PaymentMethodIcon = forwardRef(function PaymentMethodIcon(
  { name, size = 'medium', fill = 'currentColor', className, style, ...props },
  ref
) {
  const iconInfo = paymentMethodIconData[name];
  if (!iconInfo) { console.warn(`PaymentMethodIcon "${name}" not found`); return null; }
  const dimension = typeof size === 'number' ? size : PAYMENT_METHOD_ICON_SIZES[size] || PAYMENT_METHOD_ICON_SIZES.medium;
  const { viewBox, paths } = iconInfo;
  return (
    <svg ref={ref} width={dimension} height={dimension} viewBox={viewBox} fill="none" xmlns="http://www.w3.org/2000/svg" className={className} style={{ display: 'inline-block', verticalAlign: 'middle', ...style }} aria-hidden="true" {...props}>
      {paths.map((path, i) => <path key={i} d={path.d} fill={path.fill || fill} fillRule={path.fillRule} clipRule={path.clipRule} opacity={path.opacity} />)}
    </svg>
  );
});

// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

export const getIconNames = () => Object.keys(iconPaths);
export const hasIcon = (name) => name in iconPaths;

export const getBrandIconNames = () => Object.keys(brandIconData);
export const hasBrandIcon = (name) => name in brandIconData;

export const getFlagIconNames = () => Object.keys(flagIconData);
export const hasFlagIcon = (name) => name in flagIconData;

export const getCardIconNames = () => Object.keys(cardIconData);
export const hasCardIcon = (name) => name in cardIconData;

export const getPaymentMethodIconNames = () => Object.keys(paymentMethodIconData);
export const hasPaymentMethodIcon = (name) => name in paymentMethodIconData;

// Default export for convenience
export default { Icon, BrandIcon, FlagIcon, CardIcon, PaymentMethodIcon };
